import sys

def main():
    input = sys.stdin.read().split()
    N = int(input[0])
    A = list(map(int, input[1:]))

    color_positions = {}
    for idx, color in enumerate(A):
        color_positions[color] = color_positions.get(color, []) + [idx]

    count = 0
    for positions in color_positions.values():
        if positions[1] - positions[0] == 2:
            count += 1
    print(count)

if __name__ == "__main__":
    main()
